/**
 * 生成 iconify 本地图标捆绑包。
 * 将项目用到的所有图标从 CDN 抓取 body + alias，生成 TypeScript bundle，
 * 应用启动时注册到 iconify，完全离线工作。
 */

import { fileURLToPath } from 'url';
import path from 'path';
import fs from 'fs';

// 以下为项目代码中实际使用的图标名称（含 alias）。
// script 会从 CDN 获取实际 parent body + alias 映射。
const LUCIDE_ICONS = [
  'alert-circle', 'alert-triangle', 'app-window', 'arrow-down', 'arrow-up',
  'arrow-up-down', 'bookmark', 'box', 'bug', 'camera', 'check', 'check-circle',
  'chevron-left', 'circle', 'circle-dot', 'clock', 'cloud', 'cloud-sun',
  'columns', 'compass', 'contrast', 'cube', 'cube-3d', 'curl', 'download',
  'droplet', 'external-link', 'eye', 'fast-forward', 'feather', 'file-code-2',
  'flask-conical', 'folder', 'folder-open', 'gauge', 'git-branch', 'grid',
  'grid-3x3', 'hand', 'help-circle', 'home', 'image', 'images', 'info',
  'layers', 'lightbulb', 'maximize', 'maximize-2', 'monitor', 'mouse-pointer',
  'move', 'move-horizontal', 'move-vertical', 'music', 'package', 'palette',
  'play', 'play-circle', 'plug', 'plus', 'rainbow', 'refresh-ccw', 'refresh-cw',
  'repeat', 'rotate-ccw', 'rotate-cw', 'ruler', 'save', 'scan-line', 'search',
  'settings', 'shield', 'shirt', 'sliders', 'smile', 'sparkles', 'star',
  'stop-circle', 'sun', 'tag', 'trash-2', 'triangle', 'upload', 'user',
  'video', 'volume-2', 'waves', 'wind', 'wrench', 'x', 'zap', 'zoom-in',
];

const TABLER_ICONS = ['cube-3d-sphere'];

async function fetchCollection(prefix, icons) {
  // 用别名名请求，API 会返回 parent body + aliases 映射
  const url = `https://api.iconify.design/${prefix}.json?icons=${icons.join(',')}`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch ${prefix}: ${res.status}`);
  return res.json();
}

async function main() {
  const outPath = path.join(
    path.dirname(fileURLToPath(import.meta.url)),
    '..', 'frontend', 'src', 'core', 'icons-bundle.ts'
  );

  console.log('Fetching Lucide icons...');
  const lucideData = await fetchCollection('lucide', LUCIDE_ICONS);

  console.log('Fetching Tabler icons...');
  const tablerData = await fetchCollection('tabler', TABLER_ICONS);

  // 统计
  const lucideCount = Object.keys(lucideData.icons ?? {}).length;
  const lucideAliasCount = Object.keys(lucideData.aliases ?? {}).length;
  const tablerCount = Object.keys(tablerData.icons ?? {}).length;
  const notFound = lucideData.not_found ?? [];

  const content = `// Auto-generated by scripts/gen-icon-bundle.mjs
// Do not edit manually. Run: cd frontend && node ../scripts/gen-icon-bundle.mjs

import { addCollection } from 'iconify-icon';

const LUCIDE_BUNDLE = ${JSON.stringify({
    prefix: 'lucide',
    icons: lucideData.icons,
    aliases: lucideData.aliases,
    width: lucideData.width ?? 24,
    height: lucideData.height ?? 24,
}, null, 2)};

const TABLER_BUNDLE = ${JSON.stringify({
    prefix: 'tabler',
    icons: tablerData.icons,
    aliases: tablerData.aliases,
    width: tablerData.width ?? 24,
    height: tablerData.height ?? 24,
}, null, 2)};

export function registerIconBundle(): void {
  addCollection(LUCIDE_BUNDLE);
  addCollection(TABLER_BUNDLE);
}
`;

  fs.writeFileSync(outPath, content, 'utf-8');
  console.log(`\n✅ Bundle written to: ${outPath}`);
  console.log(`   Lucide: ${lucideCount} icons + ${lucideAliasCount} aliases`);
  console.log(`   Tabler: ${tablerCount} icons`);
  if (notFound.length > 0) {
    console.log(`   ⚠ Not found (will fall back to CDN): ${notFound.join(', ')}`);
  }
}

main().catch(console.error);
